DO $$ BEGIN CREATE TYPE "MapListingStatus" AS ENUM ('PENDING', 'APPROVED', 'REJECTED', 'SUSPENDED'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "OwnershipRole" AS ENUM ('OWNER', 'MANAGER'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "ClaimRequestStatus" AS ENUM ('PENDING', 'APPROVED', 'REJECTED'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "AnalyticsEventType" AS ENUM ('LISTING_VIEW', 'WEBSITE_CLICK', 'WHATSAPP_CLICK', 'PHONE_CLICK', 'DIRECTIONS_CLICK'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS "cart_events" ("id" TEXT NOT NULL,"shop_id" TEXT NOT NULL,"product_id" TEXT NOT NULL,"user_id" TEXT,"session_id" TEXT,"customer_name" TEXT,"customer_email" TEXT,"customer_phone" TEXT,"event" TEXT NOT NULL,"quantity" INTEGER NOT NULL DEFAULT 1,"unit_price" DOUBLE PRECISION NOT NULL DEFAULT 0,"currency" TEXT NOT NULL DEFAULT 'EGP',"metadata" JSONB,"is_recovered" BOOLEAN NOT NULL DEFAULT false,"recovered_at" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "cart_events_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listings" ("id" TEXT NOT NULL,"linked_shop_id" TEXT,"title" TEXT NOT NULL,"category" TEXT,"description" TEXT,"website_url" TEXT,"phone" TEXT,"whatsapp" TEXT,"social_links" JSONB,"logo_url" TEXT,"cover_url" TEXT,"status" "MapListingStatus" NOT NULL DEFAULT 'PENDING',"review_note" TEXT,"reviewed_at" TIMESTAMP(3),"reviewed_by_admin_id" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "map_listings_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listing_branches" ("id" TEXT NOT NULL,"listing_id" TEXT NOT NULL,"name" TEXT,"latitude" DOUBLE PRECISION NOT NULL,"longitude" DOUBLE PRECISION NOT NULL,"address_label" TEXT,"governorate" TEXT,"city" TEXT,"phone" TEXT,"is_primary" BOOLEAN NOT NULL DEFAULT false,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "map_listing_branches_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listing_owners" ("id" TEXT NOT NULL,"phone" TEXT,"name" TEXT,"email" TEXT,"password_hash" TEXT,"avatar_url" TEXT,"is_active" BOOLEAN NOT NULL DEFAULT true,"last_login" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "map_listing_owners_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listing_ownerships" ("id" TEXT NOT NULL,"listing_id" TEXT NOT NULL,"owner_id" TEXT NOT NULL,"role" "OwnershipRole" NOT NULL DEFAULT 'OWNER',"granted_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "map_listing_ownerships_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listing_claim_requests" ("id" TEXT NOT NULL,"listing_id" TEXT NOT NULL,"owner_id" TEXT NOT NULL,"otp_verified" BOOLEAN NOT NULL DEFAULT false,"status" "ClaimRequestStatus" NOT NULL DEFAULT 'PENDING',"admin_note" TEXT,"reviewed_at" TIMESTAMP(3),"reviewed_by" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "map_listing_claim_requests_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "map_listing_analytics_events" ("id" TEXT NOT NULL,"listing_id" TEXT NOT NULL,"type" "AnalyticsEventType" NOT NULL,"ip" TEXT,"user_agent" TEXT,"meta" JSONB,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "map_listing_analytics_events_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "portal_otp_codes" ("id" TEXT NOT NULL,"phone" TEXT NOT NULL,"code_hash" TEXT NOT NULL,"purpose" TEXT NOT NULL DEFAULT 'login',"attempts" INTEGER NOT NULL DEFAULT 0,"verified" BOOLEAN NOT NULL DEFAULT false,"expires_at" TIMESTAMP(3) NOT NULL,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "portal_otp_codes_pkey" PRIMARY KEY ("id"));
